from flask import Flask, jsonify, request
import json
from flask_sqlalchemy import SQLAlchemy
from flask_marshmallow import Marshmallow
from flask_cors import CORS
from flask_bcrypt import Bcrypt
from flask_jwt_extended import JWTManager


app = Flask(__name__)
CORS(app)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///database.db'
app.config['JWT_SECRET_KEY'] = 'secret' # Change this!

db = SQLAlchemy(app)
ma = Marshmallow(app)
bcrypt = Bcrypt(app)
jwt = JWTManager(app)


class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(150), unique=True)
    username = db.Column(db.String(30), unique=True)
    accountType = db.Column(db.String(20))
    credits = db.Column(db.Integer, default=0)
    referralCode = db.Column(db.String(150))
    verifiedStatus = db.Column(db.Boolean(), default=False)

class UserSchema(ma.Schema):
    class Meta:
        fields = ('id', 'email', 'username', 'accountType', 'credits', 'referralCode', 'verifiedStatus')


user_schema = UserSchema()
users_schema = UserSchema(many=True)


@app.route('/users', methods=['GET'])
def getUsers():
    allUsers = User.query.all()
    result = users_schema.dump(allUsers)
    return jsonify(result), 200


@app.route('/user/<int:id>', methods=['GET'])
def getUserById(id):
    user = User.query.get(id)
    result = user_schema.dump(user)
    return jsonify(result), 200


@app.route('/user', methods=['POST'])
def addUser():
    email = request.json['email']
    username = request.json['username']
    accountType = request.json['accountType']

    new_user = User(
        email=email, 
        username=username, 
        accountType=accountType)
    
    db.session.add(new_user)
    db.session.commit()

    result = user_schema.dump(new_user)
    return jsonify(result), 201


@app.route('/user/<int:id>', methods=['PUT'])
def updateUserById(id):
    user = User.query.get(id)
    
    email = request.json['email'] if 'email' in request.json else None
    username = request.json['username'] if 'username' in request.json else None
    accountType = request.json['accountType'] if 'accountType' in request.json else None

    if email is not None:
        user.email = email
    
    if username is not None:
        user.username = username
    
    if accountType is not None:
        user.accountType = accountType

    db.session.commit()
    result = user_schema.dump(user)
    return jsonify(result), 201


@app.route('/user/<int:id>', methods=['DELETE'])
def deleteUserById(id):
    user = User.query.get(id)
    db.session.delete(user)
    db.session.commit()

    result = user_schema.dump(user)
    return jsonify(result), 204


if __name__ == '__main__':
    app.run(debug=True)